package com.example.biometricauth;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;

import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import java.util.concurrent.Executor;

public class LoginActivity extends AppCompatActivity {

    public static final String PREFS_NAME = "auth_prefs";
    public static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    public static final String KEY_AUTHENTICATED = "authenticated";

    private EditText usernameEditText;
    private EditText passwordEditText;
    private CheckBox biometricCheckBox;
    private Button loginButton;
    private Button biometricButton;

    private SharedPreferences sharedPreferences;
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);

        if (sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false) && canUseBiometric()) {
            authenticateWithBiometricAndNavigate();
            return;
        }

        setContentView(R.layout.activity_login);

        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        biometricCheckBox = findViewById(R.id.biometricCheckBox);
        loginButton = findViewById(R.id.loginButton);
        biometricButton = findViewById(R.id.biometricButton);

        biometricCheckBox.setChecked(sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false));

        setupBiometricPrompt();

        loginButton.setOnClickListener(v -> handleLogin());

        biometricButton.setOnClickListener(v -> {
            if (sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false)) {
                authenticateWithBiometricAndNavigate();
            } else {
                Toast.makeText(this, "Enable biometric login first", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void handleLogin() {
        String username = usernameEditText.getText().toString().trim();
        String password = passwordEditText.getText().toString().trim();

        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Enter username and password", Toast.LENGTH_SHORT).show();
            return;
        }

        if (isValidCredentials(username, password)) {
            boolean biometricEnabled = biometricCheckBox.isChecked();
            sharedPreferences.edit()
                    .putBoolean(KEY_BIOMETRIC_ENABLED, biometricEnabled)
                    .putBoolean(KEY_AUTHENTICATED, true)
                    .apply();

            navigateToHome();
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
        }
    }

    private boolean isValidCredentials(String username, String password) {
        return username.equals("user") && password.equals("password");
    }

    private void setupBiometricPrompt() {
        Executor executor = ContextCompat.getMainExecutor(this);
        biometricPrompt = new BiometricPrompt(this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                sharedPreferences.edit().putBoolean(KEY_AUTHENTICATED, true).apply();
                navigateToHome();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Toast.makeText(LoginActivity.this, "Fingerprint not recognized", Toast.LENGTH_SHORT).show();
            }

            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Toast.makeText(LoginActivity.this, errString, Toast.LENGTH_SHORT).show();
            }
        });

        promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Biometric Login")
                .setSubtitle("Unlock with your fingerprint")
                .setNegativeButtonText("Cancel")
                .build();
    }

    private void authenticateWithBiometricAndNavigate() {
        if (!canUseBiometric()) {
            Toast.makeText(this, "Biometric authentication unavailable", Toast.LENGTH_SHORT).show();
            if (!isFinishing()) {
                setContentView(R.layout.activity_login);
                initializeViewsAfterFallback();
            }
            return;
        }

        if (biometricPrompt == null || promptInfo == null) {
            setupBiometricPrompt();
        }

        biometricPrompt.authenticate(promptInfo);
    }

    private void initializeViewsAfterFallback() {
        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        biometricCheckBox = findViewById(R.id.biometricCheckBox);
        loginButton = findViewById(R.id.loginButton);
        biometricButton = findViewById(R.id.biometricButton);

        biometricCheckBox.setChecked(sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false));

        loginButton.setOnClickListener(v -> handleLogin());

        biometricButton.setOnClickListener(v -> {
            if (sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false)) {
                authenticateWithBiometricAndNavigate();
            } else {
                Toast.makeText(this, "Enable biometric login first", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private boolean canUseBiometric() {
        BiometricManager biometricManager = BiometricManager.from(this);
        int result = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);
        return result == BiometricManager.BIOMETRIC_SUCCESS;
    }

    private void navigateToHome() {
        Intent intent = new Intent(this, MainActivity.class);
        startActivity(intent);
        finish();
    }
}

package com.example.biometricauth;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.widget.Button;

import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    private SharedPreferences sharedPreferences;
    private Button logoutButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        sharedPreferences = getSharedPreferences(LoginActivity.PREFS_NAME, Context.MODE_PRIVATE);

        if (!sharedPreferences.getBoolean(LoginActivity.KEY_AUTHENTICATED, false)) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_main);

        logoutButton = findViewById(R.id.logoutButton);
        logoutButton.setOnClickListener(v -> {
            sharedPreferences.edit().putBoolean(LoginActivity.KEY_AUTHENTICATED, false).apply();
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        });
    }
}

package com.example.biometricauth;

import android.app.Application;
import android.content.Context;
import android.content.SharedPreferences;

public class AuthApp extends Application {

    @Override
    public void onCreate() {
        super.onCreate();
        SharedPreferences preferences = getSharedPreferences(LoginActivity.PREFS_NAME, Context.MODE_PRIVATE);
        if (!preferences.getBoolean(LoginActivity.KEY_BIOMETRIC_ENABLED, false)) {
            preferences.edit().putBoolean(LoginActivity.KEY_AUTHENTICATED, false).apply();
        }
    }
}

